/**
 * GeminiFileSearchChatModel
 *
 * A custom LangChain chat model that integrates Gemini's File Search
 * capability directly into the model, enabling single API call RAG queries.
 *
 * CONFIGURATION: Update the CONFIG object below with your settings.
 */

const { BaseChatModel } = require('@langchain/core/language_models/chat_models');
const { AIMessage } = require('@langchain/core/messages');

// ============================================
// CONFIGURATION - UPDATE THESE VALUES
// ============================================
const CONFIG = {
  // Your Gemini API key (or use credential reference)
  apiKey: 'YOUR_GEMINI_API_KEY',

  // Model to use
  model: 'gemini-2.5-flash',

  // File Search Store names - REQUIRED
  // Format: 'fileSearchStores/your-store-name'
  storeNames: [
    'fileSearchStores/your-store-name'
  ],

  // Optional: Metadata filter (AIP-160 format)
  // Example: 'category="docs" AND version>1.0'
  metadataFilter: '',

  // Generation parameters
  temperature: 0.7,
  maxOutputTokens: 2048,
};
// ============================================

class GeminiFileSearchChatModel extends BaseChatModel {
  constructor(config = {}) {
    super({});
    this.apiKey = config.apiKey || CONFIG.apiKey;
    this.modelName = config.model || CONFIG.model;
    this.storeNames = config.storeNames || CONFIG.storeNames;
    this.metadataFilter = config.metadataFilter || CONFIG.metadataFilter;
    this.temperature = config.temperature ?? CONFIG.temperature;
    this.maxOutputTokens = config.maxOutputTokens ?? CONFIG.maxOutputTokens;
  }

  _llmType() {
    return 'gemini-file-search';
  }

  _convertMessages(messages) {
    const contents = [];
    for (const msg of messages) {
      const msgType = msg._getType();
      const content = typeof msg.content === 'string'
        ? msg.content
        : JSON.stringify(msg.content);

      if (msgType === 'system') {
        contents.push({
          role: 'user',
          parts: [{ text: content }],
        });
        contents.push({
          role: 'model',
          parts: [{ text: 'Understood. I will follow these instructions.' }],
        });
      } else if (msgType === 'human') {
        contents.push({
          role: 'user',
          parts: [{ text: content }],
        });
      } else if (msgType === 'ai') {
        contents.push({
          role: 'model',
          parts: [{ text: content }],
        });
      }
    }
    return contents;
  }

  async _callGeminiApi(contents) {
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${this.modelName}:generateContent?key=${this.apiKey}`;

    const body = {
      contents,
      tools: [{
        fileSearch: {
          fileSearchStoreNames: this.storeNames,
          ...(this.metadataFilter && { metadataFilter: this.metadataFilter }),
        },
      }],
      generationConfig: {
        temperature: this.temperature,
        maxOutputTokens: this.maxOutputTokens,
      },
    };

    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      const error = await response.text();
      throw new Error(`Gemini API error: ${response.status} - ${error}`);
    }

    return response.json();
  }

  async _generate(messages, options, runManager) {
    const contents = this._convertMessages(messages);
    const response = await this._callGeminiApi(contents);

    const candidate = response.candidates?.[0];
    const text = candidate?.content?.parts?.[0]?.text ?? '';
    const groundingMetadata = candidate?.groundingMetadata;

    const aiMessage = new AIMessage({
      content: text,
      additional_kwargs: {
        groundingMetadata,
        groundingChunks: groundingMetadata?.groundingChunks,
        groundingSupports: groundingMetadata?.groundingSupports,
        usageMetadata: response.usageMetadata,
        finishReason: candidate?.finishReason,
      },
    });

    return {
      generations: [{
        text,
        message: aiMessage,
        generationInfo: {
          finishReason: candidate?.finishReason,
          groundingChunks: groundingMetadata?.groundingChunks?.length ?? 0,
          totalTokens: response.usageMetadata?.totalTokenCount,
        },
      }],
      llmOutput: {
        tokenUsage: {
          promptTokens: response.usageMetadata?.promptTokenCount,
          completionTokens: response.usageMetadata?.candidatesTokenCount,
          totalTokens: response.usageMetadata?.totalTokenCount,
        },
      },
    };
  }

  bindTools(tools) {
    console.warn('GeminiFileSearchChatModel: bindTools not supported');
    return this;
  }
}

return new GeminiFileSearchChatModel();

// Extract grounding metadata from AI Agent response
const response = $input.first().json;

// Get the output text
const outputText = response.output || '';

// Get grounding chunks (source citations)
const groundingChunks = response.additional_kwargs?.groundingChunks || [];

// Format citations
const citations = groundingChunks.map((chunk, index) => ({
  index: index + 1,
  title: chunk.retrievedContext?.title || 'Unknown',
  text: chunk.retrievedContext?.text?.substring(0, 200) + '...' || '',
  store: chunk.retrievedContext?.fileSearchStore || 'Unknown'
}));

// Get token usage
const tokenUsage = response.additional_kwargs?.usageMetadata || {};

return {
  answer: outputText,
  citations: citations,
  citationCount: citations.length,
  tokenUsage: {
    prompt: tokenUsage.promptTokenCount || 0,
    completion: tokenUsage.candidatesTokenCount || 0,
    total: tokenUsage.totalTokenCount || 0
  }
};
